rows.customCode:
(() => {
  // pcbw: Image-Oriented Creative Director Bot - prompt builder with style management
  if (window.__pcbw_imgDirectorInit) return;
  window.__pcbw_imgDirectorInit = true;

  var STYLE_PRESETS = {
    photorealistic: {
      prefix: "photorealistic, high detail, natural lighting, sharp focus, 8k uhd",
      suffix: "professional photography, DSLR, depth of field, ray tracing",
      negative: "cartoon, anime, painting, blurry, low quality"
    },
    anime: {
      prefix: "anime style, cel shaded, vibrant colors, clean lines",
      suffix: "studio quality, detailed background, professional anime art",
      negative: "photorealistic, 3d render, blurry, deformed"
    },
    oilpainting: {
      prefix: "oil painting, classical art style, rich textures, masterful brushwork",
      suffix: "museum quality, canvas texture, chiaroscuro lighting, fine art",
      negative: "digital art, anime, photograph, low quality"
    },
    concept: {
      prefix: "concept art, digital painting, cinematic composition, professional",
      suffix: "trending on artstation, matte painting, highly detailed environment",
      negative: "photo, anime, blurry, amateur"
    },
    watercolor: {
      prefix: "watercolor painting, soft washes, delicate brushstrokes, paper texture",
      suffix: "artistic, flowing colors, translucent layers, fine art watercolor",
      negative: "digital, photorealistic, harsh lines, 3d render"
    }
  };

  function initImageState() {
    oc.thread.customData ||= {};
    if (!oc.thread.customData.__pcbw_activeStyle) {
      oc.thread.customData.__pcbw_activeStyle = "photorealistic";
    }
    if (!Array.isArray(oc.thread.customData.__pcbw_promptHistory)) {
      oc.thread.customData.__pcbw_promptHistory = [];
    }
    if (typeof oc.thread.customData.__pcbw_promptCount !== "number") {
      oc.thread.customData.__pcbw_promptCount = 0;
    }
  }

  function getActivePreset() {
    initImageState();
    var key = oc.thread.customData.__pcbw_activeStyle;
    return STYLE_PRESETS[key] || STYLE_PRESETS.photorealistic;
  }

  function buildImagePrompt(subject) {
    var preset = getActivePreset();
    return preset.prefix + ", " + subject + ", " + preset.suffix;
  }

  // Apply image prompt fields based on active style
  function applyStyleToCharacter() {
    var preset = getActivePreset();
    oc.character.imagePromptPrefix = preset.prefix;
    oc.character.imagePromptSuffix = preset.suffix;
  }

  // Initialize on load
  initImageState();
  applyStyleToCharacter();

  oc.thread.on("MessageAdded", function(msg) {
    if (msg.author !== "user") return;
    initImageState();
    var text = (msg.content || "").trim();
    var lower = text.toLowerCase();

    // Style switching: /style <name>
    if (lower.startsWith("/style ")) {
      var styleName = lower.slice(7).trim();
      if (STYLE_PRESETS[styleName]) {
        oc.thread.customData.__pcbw_activeStyle = styleName;
        applyStyleToCharacter();
        oc.thread.messages.push({
          author: "system",
          content: "Style switched to: " + styleName + "\nPrefix: " + STYLE_PRESETS[styleName].prefix + "\nSuffix: " + STYLE_PRESETS[styleName].suffix,
          hiddenFrom: ["ai"],
          expectsReply: false
        });
      } else {
        oc.thread.messages.push({
          author: "system",
          content: "Unknown style. Available: " + Object.keys(STYLE_PRESETS).join(", "),
          hiddenFrom: ["ai"],
          expectsReply: false
        });
      }
      return;
    }

    // Prompt building: /prompt <subject>
    if (lower.startsWith("/prompt ")) {
      var subject = text.slice(8).trim();
      var fullPrompt = buildImagePrompt(subject);
      oc.thread.customData.__pcbw_promptCount += 1;
      oc.thread.customData.__pcbw_promptHistory.push({
        subject: subject,
        style: oc.thread.customData.__pcbw_activeStyle,
        full: fullPrompt
      });

      oc.thread.messages.push({
        author: "system",
        content: "--- Generated Image Prompt ---\nStyle: " + oc.thread.customData.__pcbw_activeStyle + "\nSubject: " + subject + "\n\nFull prompt:\n" + fullPrompt + "\n\nNegative prompt:\n" + getActivePreset().negative,
        hiddenFrom: [],
        expectsReply: false
      });
      return;
    }

    // Show current style info
    if (lower === "/info") {
      var style = oc.thread.customData.__pcbw_activeStyle;
      var preset = getActivePreset();
      var count = oc.thread.customData.__pcbw_promptCount;
      oc.thread.messages.push({
        author: "system",
        content: "Active style: " + style + "\nPrompts generated: " + count + "\nPrefix: " + preset.prefix + "\nSuffix: " + preset.suffix + "\nNegative: " + preset.negative,
        hiddenFrom: ["ai"],
        expectsReply: false
      });
      return;
    }

    // Show prompt history
    if (lower === "/history") {
      var history = oc.thread.customData.__pcbw_promptHistory;
      if (history.length === 0) {
        oc.thread.messages.push({
          author: "system",
          content: "No prompts generated yet. Try /prompt <subject>",
          hiddenFrom: ["ai"],
          expectsReply: false
        });
      } else {
        var lines = history.slice(-5).map(function(h, i) {
          return (i + 1) + ". [" + h.style + "] " + h.subject;
        });
        oc.thread.messages.push({
          author: "system",
          content: "--- Recent Prompts ---\n" + lines.join("\n"),
          hiddenFrom: ["ai"],
          expectsReply: false
        });
      }
      return;
    }
  });

  // Inject art direction context into AI responses
  oc.thread.on("MessageAdding", function(msg) {
    if (msg.author !== "ai") return;
    initImageState();
    var style = oc.thread.customData.__pcbw_activeStyle;
    var count = oc.thread.customData.__pcbw_promptCount;
    var context = "[ART DIRECTION] Active style: " + style + ". Prompts crafted so far: " + count + ".";
    context += " When the user asks about images or art, frame your advice in terms of the active style.";
    context += " When describing visual concepts, be specific about composition, lighting, color palette, and mood.";
    oc.character.reminderMessage = context;
  });
})();
